#include <stdio.h>
#include <limits.h>

int minEnergy(int n, int* heights, int k) {
    int* dp = (int*)malloc(n * sizeof(int));
    dp[0] = 0;
    for (int i = 1; i < n; i++) {
        dp[i] = INT_MAX;
        for (int j = 1; j <= k; j++) {
            if (i - j >= 0) {
                dp[i] = (dp[i] < dp[i - j] + abs(heights[i] - heights[i - j])) ? dp[i] : dp[i - j] + abs(heights[i] - heights[i - j]);
            }
        }
    }
    int result = dp[n - 1];
    free(dp);
    return result;
}

int main() {
    int n = 6;
    int heights[] = {30, 10, 60, 10, 60, 50};
    int k = 2;
    printf("%d\n", minEnergy(n, heights, k));
    return 0;
}

